        var result = new List<NomeID>(max);
        var lista = await reader.ListarNAsync(max, uri, where, parameters, DBFornecedoresDicInfo.CampoNome);
        if (lista == null || !lista.Any())
        {
            return result;
        }

        foreach (var item in lista)
        {
            if (token.IsCancellationRequested)
                continue;
            if (item?.FNome != null)
            {
                result.Add(new NomeID { Nome = item.FNome, ID = item.ID });
            }
        }

        return result;
    }

    public async Task<IEnumerable<FornecedoresResponseAll>> GetAll(int max, [FromRoute, Required] string uri, CancellationToken token = default)
    {
        ThrowIfDisposed();
        max = Math.Min(Math.Max(max, 1), BaseConsts.PMaxItens);
        if (!(await Uris.ValidaUriAsync(uri, _entityService)))
        {
            throw new Exception("Fornecedores: URI inválida");
        }

        var entryOptions = new HybridCacheEntryOptions
        {
            Expiration = TimeSpan.FromMinutes(BaseConsts.PMaxMinutesCache),
            LocalCacheExpiration = TimeSpan.FromMinutes(BaseConsts.PMaxMinutesCache)
        };
        using var scope = _connectionService.CreateConnectionScope(uri);
        using var oCnn = scope.Connection;
        var keyCache = await reader.ReadStringAuditorAsync(max, uri, "", [], oCnn);
        var cacheKey = $"{uri}-Fornecedores-Filter-{max}-{keyCache}";
        var result = await _cache.GetOrCreateAsync(cacheKey, async cancel => await GetDataAllAsync2(max, string.Empty, [], uri, cancel), entryOptions, cancellationToken: token);
        return result;
    }

    private async Task<IEnumerable<FornecedoresResponseAll>> GetDataAllAsync2(int max, string where, List<SqlParameter>? parameters, string uri, CancellationToken token)
    {
        using var scope = _connectionService.CreateConnectionScope(uri);
        using var oCnn = scope.Connection;
        if (oCnn == null)
        {
            throw new DatabaseConnectionException();
        }

        var result = await reader.ListarAsync(max, uri, where, parameters, string.Empty, token);
        return result;
    }
}